/* 4. Toast Popup Styles */
.toast-container {
  position: fixed;
  bottom: 40px;
  left: 50%;
  transform: translateX(-50%) translateY(30px);
  width: 90%;
  max-width: 400px;
  z-index: 1050;
  background-color: rgba(15, 23, 42, 0.95);
  backdrop-filter: blur(8px);
  border-radius: 12px;
  box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1);
  padding: 14px 18px;
  display: flex;
  align-items: center;
  gap: 12px;
  opacity: 0;
  pointer-events: none;
  transition: all 0.35s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

.toast-container.show {
  opacity: 1;
  pointer-events: auto;
  transform: translateX(-50%) translateY(0);
}

.toast-icon {
  color: #10b981;
  display: flex;
  align-items: center;
  justify-content: center;
}

.toast-text {
  font-size: 13px;
  font-weight: 500;
  color: #ffffff;
}
